# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    // Player Stats
    public static int health = 100;
    public static int currency = 0;

    // Shop Prices
    public static Dictionary<int, float> shopPrices = new Dictionary<int, float>()
    {
        {1, 10f}, // Sword: $10
        {2, 50f}  // Shield: $50
    };

    // Damage Calculation
    public static int CalculateDamage(int damageType)
    {
        if (damageType == 1) // Basic Attack
        {
            return health / 5;
        }
        else if (damageType == 2) // Magic Attack
        {
            return health * 2;
        }
        else
        {
            Debug.LogError("Invalid Damage Type");
            return 0;
        }
    }

    // Shop Purchase Functionality
    public static bool MakePurchase(int itemID)
    {
        if (shopPrices.ContainsKey(itemID))
        {
            float price = shopPrices[itemID];
            if (currency >= price)
            {
                currency -= price;
                health += CalculateDamage(CalculateItemDamage(itemID));
                return true;
            }
            else
            {
                Debug.LogError("Insufficient Currency");
            }
        }
        else
        {
            Debug.LogError("Invalid Item ID");
        }

        return false;
    }

    // Calculate Damage based on item purchase
    public static int CalculateItemDamage(int itemID)
    {
        if (itemID == 1) // Sword: +20 damage
        {
            return 20;
        }
        else if (itemID == 2) // Shield: +10 health
        {
            return 10;
        }
        else
        {
            Debug.LogError("Invalid Item ID");
            return 0;
        }
    }

    public static bool ApplyDamage(int damage)
    {
        if (health - damage >= 0)
        {
            health -= damage;
            return true;
        }
        else
        {
            health = 0;
            Debug.LogError("Player Health Fallen to 0");
            return false;
        }
    }
}